namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarization service that ranks sentences by word-frequency scores
/// and returns the top-scoring ones in their original order.
/// </summary>
public partial class DocumentSummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","must","can","could","in","on","at","to","for",
        "of","with","by","from","as","into","through","during","before","after",
        "above","below","between","out","off","over","under","then","once","here",
        "there","when","where","why","how","all","each","every","both","few",
        "more","most","other","some","such","no","not","only","own","same","so",
        "than","too","very","it","its","this","that","these","those","i","me",
        "my","we","our","you","your","he","him","his","she","her","they","them",
        "their","what","which","who","whom"
    };

    public string Summarize(string text, int maxSentences)
    {
        if (string.IsNullOrWhiteSpace(text))
            return string.Empty;

        maxSentences = Math.Max(1, maxSentences);

        var sentences = SplitSentences(text);
        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        // Build word-frequency map (excluding stop words)
        var wordFrequency = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                if (!StopWords.Contains(word) && word.Length > 1)
                    wordFrequency[word] = wordFrequency.GetValueOrDefault(word) + 1;
            }
        }

        // Score each sentence
        var scored = sentences
            .Select((s, index) => new
            {
                Sentence = s,
                Index = index,
                Score = Tokenize(s)
                    .Where(w => wordFrequency.ContainsKey(w))
                    .Sum(w => wordFrequency[w])
            })
            .OrderByDescending(x => x.Score)
            .Take(maxSentences)
            .OrderBy(x => x.Index) // preserve original order
            .Select(x => x.Sentence);

        return string.Join(" ", scored);
    }

    private static List<string> SplitSentences(string text)
    {
        // Split on sentence-ending punctuation followed by whitespace or end-of-string
        var raw = SentenceRegex().Split(text);
        return raw
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static IEnumerable<string> Tokenize(string sentence)
    {
        return WordRegex().Matches(sentence).Select(m => m.Value.ToLowerInvariant());
    }

    [GeneratedRegex(@"(?<=[.!?])\s+")]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\w+")]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _summarizer = new();

    /// <summary>
    /// Accepts a document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.DocumentText))
            return BadRequest(new { error = "DocumentText is required." });

        var summary = _summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

